module packet_filter(  
    input [7:0] src_ip,  
    input [7:0] allowed_ip,  
    output reg allow  
);  
  wire [7:0] _tap_src_ip = src_ip & {8{1'b1}};

    always @(*) begin  
        if (src_ip == allowed_ip)  
            allow = 1;  
        else  
            allow = 0;  
    end  
endmodule
